// // This is a synchronous counter that decrements on each clock edge when reset is low.
module sync_counter (
    input clk,
    input reset,
    output reg [3:0] count);
always @(posedge clk)
begin
    if (reset)
        count <= 4'b0000;
    else
        count <= count + 1;
end
endmodule
